exercise.solution:
class Point:
    def __init__(self, x, y):
        self.x, self.y = x, y

    @classmethod
    def from_string(cls, text):
        x, y = text.split(",")
        return cls(int(x), int(y))

p = Point.from_string("3,4")
print(p.x, p.y)  # 3 4
